"""
Fear Less Maths — Question Content: Levels 1 & 2
Every question hand-written. No placeholders.
Sheet 1=Intuition, Sheet 2=Concept, Sheet 3=Practice, Sheet 4=Mastery
Remedial variants replace numbers using remedialise().
"""
import random, re

def cb(title, bullets, example="", icon_diagram=None, icon_params=None):
    return {"type":"concept_box","section_title":title,
            "section_bullets":bullets,"example":example,
            "icon_diagram":icon_diagram,"icon_params":icon_params or {}}

def tb(title, tips):
    """Tips box — shown INSTEAD of concept boxes on sheet 3.
    tips: list of short tip strings."""
    return {"type":"tips_box","section_title":title,"tips":tips}

def q(text, qtype="fill", ans="Answer = ____", bold="", diag=None, dpar=None):
    return {"type":qtype,"text":text,"answer_label":ans,
            "bold_phrase":bold,"diagram_type":diag,"diagram_params":dpar or {}}


# ───────────────────────── shared pictorial-question helpers ─────────────────────────
# Used by content_pre.py (Pre-Level) and content_l1_redesign.py (Level 21) to avoid
# any plain-text-only questions -- every question gets a diagram, never bare numbers.

def q_eq1(n, op, kind="apple"):
    """n+1 or n-1 as a visual equation (mascot + objects + symbol + box),
    replacing plain text like '9 + 1 = ____'."""
    right = 1
    text = "Add the numbers." if op == "+" else "Subtract the numbers."
    return q(text, "diagram", "____", "", "visual_equation",
              {"left": n, "right": right, "kind": kind, "op": op})


def q_cmp(l, r, kind="apple"):
    """Number comparison as a wordless picture (two object groups +
    >/</= tick-boxes), replacing plain text like '47 ___ 52'."""
    return q("Compare the numbers.", "diagram", "____", "", "compare_choice",
              {"left_count": min(l, 20), "right_count": min(r, 20), "kind": kind})


def q_seq(seq, label="pattern"):
    """Number sequence with one blank shown as a row of boxes (mascot +
    boxes), replacing plain text like '5, ___, 7'."""
    text = "Find the missing number." if label == "missing" else "Find the missing number in the pattern."
    return q(text, "diagram", "____", "", "sequence_boxes",
              {"seq": seq, "label": label})


def q_cmp_big(l, r):
    """Comparison for larger numbers (e.g. 1-100) using base-10 blocks
    instead of individual object dots, since drawing 80+ dots is impractical."""
    return q("Compare the numbers.", "diagram", "____", "",
              "compare_blocks", {"left": l, "right": r})


def q_place(tens, ones):
    """Place value as base-10 blocks, with a 'Find the value' question
    after the number, replacing plain text like '3 x 10 + 4 = ____'."""
    return q("Find the value.", "diagram", "____", "",
              "base10_blocks", {"tens": tens, "ones": ones})

def remedialise(items, seed=0):
    random.seed(seed)
    out = []
    for item in items:
        if item["type"] in ("concept_box", "tips_box"):
            out.append(item); continue
        ni = dict(item)
        def sw(m):
            v = int(float(m.group()))
            if v == 0: return "0"
            d = random.randint(1, max(1, abs(v)//3 + 1))
            nv = v + d if random.random() > 0.5 else max(1, v - d)
            return str(nv)
        ni["text"] = re.sub(r'\b\d+\.?\d*\b', sw, ni.get("text",""))

        # Object-count diagrams (Pre-Level CPA sheets): make remedial EASIER by
        # shrinking the object count toward a smaller, simpler range rather than
        # randomly perturbing it like text numbers above.
        dpar = ni.get("diagram_params")
        if dpar:
            dpar = dict(dpar)
            if ni.get("diagram_type") == "object_group" and "count" in dpar:
                c = dpar["count"]
                dpar["count"] = max(1, min(c, random.randint(max(1, c - 3), c)))
                dpar["group_size"] = 5  # always simplify to rows of 5 in remedial
            elif ni.get("diagram_type") == "object_compare":
                for key in ("left_count", "right_count"):
                    if key in dpar:
                        c = dpar[key]
                        dpar[key] = max(1, min(c, random.randint(max(1, c - 2), c)))
            ni["diagram_params"] = dpar

        out.append(ni)
    return out


