PICTORIAL_LEVELS = (0, 21, 22, 23, 24, 25)


def _diagram_to_numeral(item):
    """Converts a diagram-based question into a plain, simple numeral
    question (no image) -- the CPA 'Abstract' stage. Used for the last
    5 of every 20 questions on pictorial levels, so each worksheet moves
    Concrete/Pictorial (15 image questions) -> Abstract (5 number
    questions), instead of staying pictorial for all 20."""
    dt = item.get("diagram_type")
    p = item.get("diagram_params", {}) or {}
    text = None
    if dt == "visual_equation":
        text = f"{p.get('left')} {p.get('op')} {p.get('right')} = ____"
    elif dt == "multiply_grid":
        text = f"{p.get('rows')} x {p.get('cols')} = ____"
    elif dt == "repeated_groups":
        text = f"{p.get('groups')} x {p.get('size')} = ____"
    elif dt == "object_group":
        if p.get("icon_label") == "divide":
            text = f"{p.get('count')} / {p.get('group_size')} = ____"
        else:
            n = p.get("count", 1)
            text = f"{n} + 1 = ____"
    elif dt in ("compare_choice", "compare_blocks"):
        l = p.get("left_count", p.get("left"))
        r = p.get("right_count", p.get("right"))
        text = f"{l} ___ {r}"
    elif dt == "sequence_boxes":
        seq = p.get("seq", [])
        text = ", ".join(str(v) if v is not None else "___" for v in seq)
    elif dt == "base10_blocks":
        text = f"{p.get('tens')} x 10 + {p.get('ones')} = ____"
    elif dt == "numline_jump":
        hop = p.get("hop_by", 1)
        sym = "+" if hop > 0 else "-"
        text = f"{p.get('mark')} {sym} {abs(hop)} = ____"
    elif dt == "sharing_baskets":
        text = f"{p.get('total')} / {p.get('num_baskets')} = ____"
    elif dt == "division_bar_model":
        text = f"{p.get('total')} / {p.get('parts')} = ____"
    else:
        # pair_grouping, array_grid, number_card, and any future diagram
        # type without a clean numeral equivalent: simple +1 fallback.
        n = p.get("count", p.get("n", 1))
        text = f"{n} + 1 = ____"
    new_item = dict(item)
    new_item["text"] = text
    new_item["diagram_type"] = None
    new_item["diagram_params"] = {}
    return new_item


def get_questions(sublevel_code: str, sheet_num: str, level_num: int = None) -> list:
    """
    Main entry point. Returns a list of question dicts.
    sublevel_code: e.g. '1A', '2E', '1CUM1', '2REV' — or a plain letter ('A','B'...)
                   for levels that opt into namespaced lookup (see below).
    sheet_num: '1','2','3','4' or '1R','2R','3R','4R' for remedial
    level_num: optional. Existing levels (1-20) already use globally-unique
               prefixed codes (1A, 2A...) and don't need this. Pre-Level (0)
               and any future level using plain letters (A, B, C...) MUST
               pass level_num so the lookup is namespaced as f"__L{level}__{code}"
               internally — this lets multiple levels reuse the same plain
               letters without overwriting each other's content.
    """
    is_remedial = str(sheet_num).endswith("R")
    base_sheet = int(str(sheet_num).replace("R", ""))

    # Look up the function — try namespaced key first (for levels that opted
    # into plain-letter codes via level_num), then fall back to the plain
    # code (existing levels, which already use globally-unique prefixes).
    sublevel_map = None
    if level_num is not None:
        sublevel_map = _DISPATCH.get(f"__L{level_num}__{sublevel_code}")
    if sublevel_map is None:
        sublevel_map = _DISPATCH.get(sublevel_code)

    if sublevel_map:
        fn = sublevel_map.get(base_sheet)
        items = fn() if fn else _fallback(sublevel_code, base_sheet)
    else:
        items = _fallback(sublevel_code, base_sheet)

    # Ensure exactly 20 questions (concept_boxes and tips_boxes are NOT counted)
    concept_items = [x for x in items if x["type"] in ("concept_box", "tips_box")]
    question_items = [x for x in items if x["type"] not in ("concept_box", "tips_box")]

    # Pad if fewer than 20 questions
    while len(question_items) < 20:
        if level_num in (0, 21, 22, 23, 24, 25):
            # Wordless levels: pad with a plain symbolic filler, never a sentence,
            # using varied random numbers so it's not the identical question every time
            _a, _b = random.randint(2, 9), random.randint(1, 5)
            _op = random.choice(["+", "-"]) if _a > _b else "+"
            _kinds = ["apple", "star", "balloon", "flower"]
            question_items.append(q("Add the numbers." if _op == "+" else "Subtract the numbers.",
                                     "diagram", "____", "", "visual_equation",
                                     {"left": _a, "right": _b, "kind": random.choice(_kinds), "op": _op}))
        else:
            question_items.append(q(f"{sublevel_code} Q{len(question_items)+1}: solve carefully.", "fill", "Answer = ____"))

    # Keep exactly 20 questions
    question_items = question_items[:20]

    # CPA structure for pictorial levels: questions 16-20 of every sheet
    # become simple numeral (Abstract) questions instead of staying
    # Pictorial for all 20 -- 15 image questions, then 5 number questions.
    if level_num in PICTORIAL_LEVELS:
        for i in range(15, 20):
            if question_items[i].get("diagram_type"):
                question_items[i] = _diagram_to_numeral(question_items[i])

    # Rebuild in original order: concept boxes stay, questions fill in
    result = []
    qi = 0
    for item in items:
        if item["type"] in ("concept_box", "tips_box"):
            result.append(item)
        else:
            if qi < 20:
                result.append(question_items[qi])
                qi += 1
    # Add any remaining padded questions
    while qi < 20:
        result.append(question_items[qi])
        qi += 1

    # Apply remedial number variation
    if is_remedial:
        result = remedialise(result, seed=hash(sublevel_code + str(sheet_num)) % 9999)

    return result
